import{c as s,Q as e,j as d,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Скрипт отчёта и очистки дублей аудио","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scripts/audio-dedup.md","filePath":"ru/scripts/audio-dedup.md","lastUpdated":1780017229000}'),a={name:"ru/scripts/audio-dedup.md"};function p(o,i,l,h,c,n){return e(),d("div",null,[...i[0]||(i[0]=[t(`<h1 id="скрипт-отчета-и-очистки-дублеи-аудио" tabindex="-1">Скрипт отчёта и очистки дублей аудио <a class="header-anchor" href="#скрипт-отчета-и-очистки-дублеи-аудио" aria-label="Permalink to &quot;Скрипт отчёта и очистки дублей аудио&quot;">​</a></h1><p>По возможности запускайте этот скрипт через проектное Python-окружение:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Вспомогательный инструмент для поиска дублей аудио с двумя режимами. По умолчанию он работает только на чтение: читает существующую базу данных SQLite <code>dj-track-similarity</code>, сравнивает треки внутри выбранного корня сохранённых путей и записывает отчёты в форматах JSON, оформленном XLSX и текстовом логе. С флагом <code>--apply</code> добавляется подтверждённый проход очистки, который удаляет безопасные файлы-дубли и их строки в базе данных после записи отчётов.</p><p>Используйте режим отчёта по умолчанию, когда нужны доказательства возможных дублей аудио перед очисткой библиотеки. Он намеренно консервативен: сначала всегда формирует отчёты. Разрушительная очистка запускается только с флагом <code>--apply</code> и интерактивным запросом подтверждения, и удаляет только тех кандидатов, которых отчёт пометил как безопасные.</p><p>Использование:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\audio_dedup\\audio_dedup.py --root ROOT [OPTIONS]</span></span></code></pre></div><p>Параметры:</p><ul><li><code>--db DB</code>: база данных проекта SQLite. По умолчанию <code>C:\\db\\abstracted.sqlite</code>.</li><li><code>--root ROOT</code>: обязательный корень сохранённых путей, ограничивающий круг треков-кандидатов.</li><li><code>--path-contains TEXT</code>: дополнительный фильтр по пути без учёта регистра. Можно указывать несколько раз.</li><li><code>--preset safe|balanced|aggressive</code>: пресет оценки. По умолчанию <code>safe</code>.</li><li><code>--min-score SCORE</code>: переопределяет порог дубля, заданный пресетом.</li><li><code>--limit-groups N</code>: записать не более N групп дублей.</li><li><code>--out-dir DIR</code>: каталог для отчётов. По умолчанию <code>scripts\\audio_dedup\\reports</code>.</li><li><code>--apply</code>: после записи отчётов запрашивает точную фразу подтверждения и удаляет только кандидатов, помеченных как <code>DELETE CANDIDATE</code> / <code>true_candidate</code>. Треки удаляются из SQLite только после успешного удаления их аудиофайлов.</li></ul><h2 id="пресеты" tabindex="-1">Пресеты <a class="header-anchor" href="#пресеты" aria-label="Permalink to &quot;Пресеты&quot;">​</a></h2><p>Каждый пресет задаёт порог оценки дубля по умолчанию и строгость совпадения по длительности. Флаг <code>--min-score</code> переопределяет только порог оценки; остальные параметры пресета остаются прежними.</p><table tabindex="0"><thead><tr><th>Пресет</th><th>Мин. оценка</th><th>Допуск по длительности</th><th>Когда использовать</th></tr></thead><tbody><tr><td><code>safe</code></td><td><code>0.965</code></td><td>~2 с / 1% соотношения</td><td>Консервативное обслуживание с минимумом ложных срабатываний.</td></tr><tr><td><code>balanced</code></td><td><code>0.925</code></td><td>~5 с / 2.5% соотношения</td><td>Более широкий охват, когда вы готовы проверять больше кандидатов.</td></tr><tr><td><code>aggressive</code></td><td><code>0.875</code></td><td>~15 с / 8% соотношения</td><td>Самый широкий поиск совпадений; ожидайте больше ручной проверки.</td></tr></tbody></table><h2 id="оценка" tabindex="-1">Оценка <a class="header-anchor" href="#оценка" aria-label="Permalink to &quot;Оценка&quot;">​</a></h2><p>Оценка пары объединяет доступные сигналы в одно значение в диапазоне <code>0..1</code>, нормализованное по весу сигналов, существующих для обоих треков:</p><table tabindex="0"><thead><tr><th>Сигнал</th><th>Вес</th></tr></thead><tbody><tr><td>Сходство embedding MERT</td><td><code>0.43</code></td></tr><tr><td>Сходство embedding MAEST</td><td><code>0.32</code></td></tr><tr><td>Сходство признаков SONARA</td><td><code>0.14</code></td></tr><tr><td>Сходство embedding CLAP</td><td><code>0.04</code></td></tr><tr><td>Близость длительности</td><td><code>0.05</code></td></tr></tbody></table><p>Каждой группе присваивается уровень уверенности <code>high</code>, <code>medium</code> или <code>review</code> на основе её оценки и любых блокирующих причин. Значения BPM/тональности из тегов показываются только как метаданные трека и никогда не используются для оценки дублей.</p><p>Примеры:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">preset balanced </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contains mastered</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">preset safe </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply</span></span></code></pre></div><p>Файлы вывода именуются <code>audio_dedup_report_&lt;timestamp&gt;.json</code>, <code>.xlsx</code> и <code>.log</code>. Каталог отчётов по умолчанию игнорируется git.</p><p>Книга XLSX — основной артефакт для ручной проверки человеком. Она включает:</p><ul><li><code>Summary</code>: путь к базе данных, выбранный корень, пресет, порог оценки, общее число треков в базе данных, число треков внутри выбранного корня/фильтра, количество групп дублей и кандидатов, разбивку по уверенности (<code>high</code>/<code>medium</code>/<code>review</code>) и счётчики покрытия embedding MERT/MAEST/CLAP.</li><li><code>Groups</code>: по одной строке на группу дублей, с предлагаемым треком <code>KEEP</code> и причинами, по которым он опережает остальные файлы.</li><li><code>Candidates</code>: по одной строке на кандидата-дубль, с пометкой <code>DELETE CANDIDATE</code> или <code>REVIEW MANUALLY</code>, путём оставляемого трека, прямой оценкой, доказательствами сходства и блокирующими факторами проверки.</li><li><code>Pair Evidence</code>: подробные попарные доказательства по MERT, MAEST, SONARA, CLAP и длительности, используемые на шаге группировки. Значения BPM/тональности из тегов показываются только как метаданные трека и не используются для оценки дублей; BPM из SONARA остаётся частью сигнала сходства SONARA, когда доступен.</li></ul><p>Проверяйте каждого кандидата вручную; отчёт содержит предлагаемые оставляемые треки и доказательства для удаления кандидатов.</p><p>Режим применения:</p><ol><li>Сначала скрипт записывает отчёты JSON/XLSX/лог.</li><li>Затем подсчитывает только безопасных кандидатов на удаление.</li><li>Выводит предупреждение о разрушительном действии и требует ввести в точности <code>APPLY DELETE</code>.</li><li>Удаляет только файлы, всё ещё находящиеся внутри выбранного <code>--root</code>.</li><li>Удаляет строки SQLite только для треков, чьи файлы были успешно удалены. Связанные строки в таблицах со столбцом <code>track_id</code> удаляются перед строкой в <code>tracks</code>.</li><li>Перезаписывает отчёты JSON и лог с <code>mode</code>, равным <code>apply</code>, и блоком <code>apply_result</code>, перечисляющим идентификаторы удалённых треков, удалённые пути и любые пропущенные или неудавшиеся удаления.</li></ol><p>Если вы отклоните подтверждение, отчёты останутся на диске, и ничего не будет удалено. Не используйте <code>--apply</code>, пока не проверите сформированную книгу XLSX. Автоматические тесты и рутинная проверка не должны вызывать скрипт с <code>--apply</code>.</p><p>Начинайте с пресета <code>safe</code> для обычного обслуживания библиотеки. Используйте <code>balanced</code> или <code>aggressive</code> только тогда, когда готовы проверять больше ложных срабатываний.</p>`,26)])])}const E=s(a,[["render",p]]);export{k as __pageData,E as default};
